INSERT INTO products (id, name, description, terms) VALUES ('prod_checking', 'GoTyme Everyday Account', 'High-yield checking account for everyday payments.', 'No minimum balance, free transfers, linked debit card.');
INSERT INTO products (id, name, description, terms) VALUES ('prod_savings', 'GoTyme Go Save', 'Multi-goal savings account with up to 5% interest rate.', 'Interest credited monthly, up to 5 active saving goals.');
INSERT INTO products (id, name, description, terms) VALUES ('prod_crypto', 'GoTyme Crypto Wallet', 'In-app crypto trading wallet for major coins.', 'Instant buying/selling, powered by regulated exchange partner.');
INSERT INTO products (id, name, description, terms) VALUES ('prod_gold', 'GoTyme Gold Account', 'PAXG tokenized physical gold investment account.', 'Backed by physical gold reserves, instant conversion to PHP.');
INSERT INTO product_documents (id, product_id, category, question, answer) VALUES ('doc_001', 'prod_checking', 'FAQ', 'How do I fund my GoTyme Everyday Account?', 'You can fund your account via OTC deposits at GoTyme kiosks, Robinsons retail outlets, 7-Eleven, or via instapay/PESONet bank transfers using your GoTyme account number.');
INSERT INTO product_documents (id, product_id, category, question, answer) VALUES ('doc_002', 'prod_checking', 'FAQ', 'How do I enable online payment on my debit card?', 'Open the card settings in your GoTyme app, tap ''Online Payments'', and toggle it ON. This will allow transactions on Netflix, Grab, Steam, and other web merchants.');
INSERT INTO product_documents (id, product_id, category, question, answer) VALUES ('doc_003', 'prod_checking', 'FAQ', 'Why was my card transaction declined?', 'Common reasons include: 1) Online or international payments are toggled OFF in your settings. 2) Insufficient funds. 3) You reached your daily or monthly transaction limits. 4) The card is locked, expired, or stolen. The voice concierge can tell you the exact reason if you ask.');
INSERT INTO product_documents (id, product_id, category, question, answer) VALUES ('doc_004', 'prod_savings', 'FAQ', 'How does interest on Go Save work?', 'Go Save offers up to 5% annual interest. Interest is computed daily on your balance and credited to your account on the 1st of every month.');
INSERT INTO product_documents (id, product_id, category, question, answer) VALUES ('doc_005', 'prod_crypto', 'FAQ', 'What are the crypto wallet trading limits?', 'Standard users can buy up to 50,000 PHP worth of crypto daily. High risk or unverified users must undergo supplemental KYC to buy crypto.');
INSERT INTO product_documents (id, product_id, category, question, answer) VALUES ('doc_006', 'prod_gold', 'FAQ', 'Is the gold account safe?', 'Yes, the GoTyme Gold account uses PAX Gold (PAXG), where each token is backed by one fine troy ounce of physical gold stored in professional London vaults. You own the gold.');
INSERT INTO product_documents (id, product_id, category, question, answer) VALUES ('doc_007', 'prod_checking', 'FAQ', 'How do I temporarily freeze my card?', 'If you misplace your physical card, you can immediately lock it in card settings by toggling the freeze card option. You can unfreeze it instantly when found.');
INSERT INTO product_documents (id, product_id, category, question, answer) VALUES ('doc_008', 'prod_checking', 'FAQ', 'What should I do if my card is stolen?', 'If your card is stolen, freeze it immediately. Then, request a replacement card in the app or call support. Do not attempt to unfreeze a stolen card.');
INSERT INTO product_documents (id, product_id, category, question, answer) VALUES ('doc_009', 'prod_checking', 'FAQ', 'How long does a card replacement take?', 'Virtual cards are generated instantly. A physical debit card can be printed instantly at any GoTyme kiosk located in Robinsons supermarkets and malls.');
INSERT INTO product_documents (id, product_id, category, question, answer) VALUES ('doc_010', 'prod_savings', 'FAQ', 'Can I set up recurring transfers to my savings?', 'Yes, you can configure auto-save tasks. Choose the frequency (daily, weekly, monthly) and the amount to automatically move money from your Everyday account to your Go Save goal.');
INSERT INTO product_documents (id, product_id, category, question, answer) VALUES ('doc_011', 'prod_checking', 'FAQ', 'What is the daily ATM withdrawal limit?', 'The default daily ATM withdrawal limit is 20,000 PHP. You can increase or decrease this limit in your card security settings up to 50,000 PHP.');
INSERT INTO product_documents (id, product_id, category, question, answer) VALUES ('doc_012', 'prod_checking', 'FAQ', 'Are international transactions allowed on my card?', 'Yes, but you must enable the ''International Payments'' toggle in your card settings first to allow transactions outside of the Philippines.');
INSERT INTO product_documents (id, product_id, category, question, answer) VALUES ('doc_013', 'prod_checking', 'FAQ', 'What are the fees for sending money?', 'Bank transfers via InstaPay cost 8 PHP per transfer. Transferring money between GoTyme users is completely free, and transfers via PESONet are free but take 1 business day.');
INSERT INTO product_documents (id, product_id, category, question, answer) VALUES ('doc_014', 'prod_checking', 'FAQ', 'How do I upgrade my KYC level?', 'To fully verify your account, navigate to the verification page in your app profile, upload a valid government ID (Passport, National ID, or UMID), and complete the face verification scan.');
