INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_01', 'GR_MASK_CARD', 'Never reveal the full 16-digit card number in speech or response. Mask all but the last 4 digits.', 'block', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_02', 'GR_BLOCK_EXTERNAL_TRANSFER', 'The voice agent is strictly forbidden from initiating transfers to external bank accounts.', 'block', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_03', 'GR_BLOCK_EMAIL_CHANGE', 'Voice agents cannot modify the customer''s registered email address.', 'block', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_04', 'GR_BLOCK_PHONE_CHANGE', 'Voice agents cannot modify the customer''s registered phone number.', 'block', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_05', 'GR_BLOCK_KYC_CHANGE', 'AI Agent is unauthorized to approve or modify KYC documents and tiers directly.', 'block', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_06', 'GR_NO_INVEST_ADVICE', 'Do not give investment recommendations on gold or crypto. Offer only informational FAQs.', 'warn', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_07', 'GR_MASK_OTP', 'Never read out or request OTP passwords from the customer over the voice channel.', 'block', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_08', 'GR_MASK_CVV', 'Never read or output the card verification value (CVV) in logs or conversations.', 'block', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_09', 'GR_REQ_BIOMETRIC_HIGH_RISK', 'All high-risk actions (card replacement, unfreezing, limit changes) require step-up biometric approval.', 'block', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_10', 'GR_FROZEN_ACCOUNT_BLOCK', 'If the account status is ''frozen'', block all transaction updates, unfreezes, or gold/crypto buys.', 'block', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_11', 'GR_HIGH_RISK_CUST_ESCALATE', 'High-risk users attempting sensitive actions must be instantly transferred to human agents.', 'escalate', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_12', 'GR_LOW_CONFIDENCE_ESCALATE', 'If the NLU confidence for critical card/account actions drops below 0.85, transfer to human.', 'escalate', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_13', 'GR_KYC_EXPIRED_LIMIT', 'If KYC is expired, reject all card payments and savings interest accruals.', 'block', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_14', 'GR_BLOCK_GOLD_IF_KYC_PENDING', 'Do not allow Gold buying if the customer''s KYC status is not ''verified''.', 'block', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_15', 'GR_BLOCK_CRYPTO_IF_KYC_PENDING', 'Do not allow Crypto trading if customer KYC status is not ''verified''.', 'block', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_16', 'GR_SUSPICIOUS_LIMIT_DECREASE', 'If a transaction is flagged suspicious, restrict daily transfer limits to 5000 PHP.', 'warn', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_17', 'GR_PIN_EXCLUDE', 'Never ask the user for their ATM PIN or Web login PIN.', 'block', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_18', 'GR_FORCE_CONFIRM_LOCK', 'Card freeze requests must be explicitly confirmed with a Yes/No response.', 'warn', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_19', 'GR_FORCE_CONFIRM_LIMIT', 'Card limit modification requests require explicit user confirmation.', 'warn', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_20', 'GR_REJECT_UNVERIFIED_GOLD', 'Block gold transaction if customer nationality is from restricted jurisdictions.', 'block', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_21', 'GR_BLOCK_VIRTUAL_PHYSICAL_SWAP', 'Do not allow virtual cards to be converted directly into physical ones without biometric ID.', 'block', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_22', 'GR_LIMIT_EXCEEDED_ALERT', 'Notify the customer immediately if the requested amount exceeds daily limits.', 'warn', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_23', 'GR_STOLEN_CARD_NO_UNFREEZE', 'If a card is marked ''stolen'', block any request to unfreeze it.', 'block', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_24', 'GR_EXPIRED_CARD_NO_ONLINE', 'Reject online purchases if the card''s expiry date has passed.', 'block', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_25', 'GR_VIP_SPECIAL_ROUTING', 'VIP customers are routed to dedicated senior support queues in case of escalation.', 'escalate', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_26', 'GR_MAX_RETRY_LOCK', 'After 3 failed verification attempts, temporarily lock the voice session.', 'block', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_27', 'GR_COMPLIANCE_SIGN_OFF', 'Changes in account interest rates require compliance validation.', 'block', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_28', 'GR_NO_P2P_FOREIGN', 'Do not allow P2P transfers to customers registered outside the Philippines.', 'block', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_29', 'GR_BLOCK_CARD_DESTRUCTION', 'Only the owner can request card replacement.', 'block', 1);
INSERT INTO guardrails (id, code, rule_description, enforcement_level, is_active) VALUES ('g_30', 'GR_AUDIT_ALL_BIOMETRICS', 'Any biometric confirmation token must be recorded in the audit logs table.', 'warn', 1);
INSERT INTO demo_scenarios (id, name, description, setup_instructions) VALUES ('scn_01', 'Netflix Transaction Declined', 'Customer calls to ask why their Netflix subscription failed. The agent discovers online payment is disabled on their card.', '1. Find card for cust_001. 2. Verify online_payment_enabled = 0. 3. Explain and offer to enable it.');
INSERT INTO demo_scenarios (id, name, description, setup_instructions) VALUES ('scn_02', 'Amazon Declined - Daily Limit', 'VIP customer attempts a purchase on Amazon but gets declined due to hitting the daily limit.', '1. Find transactions for cust_006. 2. Locate declined Amazon transaction (daily_limit). 3. Offer to update daily limit (requires biometric).');
INSERT INTO demo_scenarios (id, name, description, setup_instructions) VALUES ('scn_03', 'KYC Pending Verification', 'Customer check why they cannot open a Gold Savings goal. The agent flags that their uploaded passport is still under review.', '1. Query kyc_status for cust_002. 2. Check kyc_documents status (pending_review).');
INSERT INTO demo_scenarios (id, name, description, setup_instructions) VALUES ('scn_04', 'Savings Goal Interest Check', 'Customer asks for their interest rates on their active savings account goals.', '1. Retrieve accounts for cust_007. 2. Get interest rate for savings account type (5.0%).');
INSERT INTO demo_scenarios (id, name, description, setup_instructions) VALUES ('scn_05', 'Unfreeze Frozen Account Block', 'A high-risk customer with a frozen account status tries to unfreeze their debit card. The agent must decline and escalate.', '1. Inspect account_status for cust_004 (frozen). 2. Trigger frozen block guardrail. 3. Escalate session.');
INSERT INTO demo_scenarios (id, name, description, setup_instructions) VALUES ('scn_06', 'Stolen Card Replacement Request', 'Customer reports they lost their physical card at a grocery store and wants it replaced.', '1. Lock card for cust_001 (stolen). 2. Create pending card replacement. 3. Ask for biometric confirmation.');
