INSERT INTO conversation_history (id, voice_session_id, role, message, tool_called, timestamp) VALUES ('ch_001','sess_001','user','Hi, I tried to pay for Netflix with my card just now, but it got declined. Can you help?',NULL,'2026-07-09 20:16:10');
INSERT INTO conversation_history (id, voice_session_id, role, message, tool_called, timestamp) VALUES ('ch_002','sess_001','assistant','Hello! Let me check that for you. I see a declined transaction of 549 PHP at Netflix. It was declined because Online Payments are disabled on your virtual card. Would you like me to enable Online Payments for you?','getRecentTransactions','2026-07-09 20:16:40');
INSERT INTO conversation_history (id, voice_session_id, role, message, tool_called, timestamp) VALUES ('ch_003','sess_001','user','Yes please, enable it.',NULL,'2026-07-09 20:17:00');
INSERT INTO conversation_history (id, voice_session_id, role, message, tool_called, timestamp) VALUES ('ch_004','sess_001','assistant','Sure! I have generated a request to enable Online Payments on your virtual card ending in 1234. Please confirm this action.','enableOnlinePayment','2026-07-09 20:17:25');
INSERT INTO conversation_history (id, voice_session_id, role, message, tool_called, timestamp) VALUES ('ch_005','sess_006','user','Hey, I lost my physical card. I need to lock it and get a replacement.',NULL,'2026-07-09 23:26:15');
INSERT INTO conversation_history (id, voice_session_id, role, message, tool_called, timestamp) VALUES ('ch_006','sess_006','assistant','I am sorry to hear that. I will freeze your physical card right away for security. I can also request a replacement physical card which you can print at any GoTyme kiosk. Shall we proceed with freezing and replacing your card?','freezeCard','2026-07-09 23:26:45');
INSERT INTO conversation_history (id, voice_session_id, role, message, tool_called, timestamp) VALUES ('ch_007','sess_006','user','Yes, go ahead.',NULL,'2026-07-09 23:27:00');
INSERT INTO conversation_history (id, voice_session_id, role, message, tool_called, timestamp) VALUES ('ch_008','sess_006','assistant','I''ve locked your card. Now, I need you to verify with your fingerprint on the phone popup to approve the replacement.','replaceCard','2026-07-09 23:27:30');
